@app.route('/setup-mfa', methods=['GET', 'POST'])
@login_required
def setup_mfa():
    if current_user.mfa_enabled:
        flash('MFA is already enabled for your account.', 'info')
        return redirect(url_for('profile'))

    if not current_user.mfa_secret:
        # Generate a new secret if one doesn't exist for the user
        current_user.mfa_secret = pyotp.random_base32()
        # Save user object (in a real app, update DB)
        users[current_user.id] = current_user

    totp = pyotp.TOTP(current_user.mfa_secret)
    provisioning_uri = totp.provisioning_uri(name=current_user.email, issuer_name="Flask MFA App")

    # Generate QR code
    img = qrcode.make(provisioning_uri)
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    qr_code_base64 = base64.b64encode(buf.getvalue()).decode('utf-8')

    if request.method == 'POST':
        otp_code = request.form.get('otp_code')
        if not otp_code:
            flash('Please enter the code from your authenticator app.', 'warning')
            return render_template('setup_mfa.html', qr_code=qr_code_base64, secret=current_user.mfa_secret)

        if totp.verify(otp_code):
            current_user.mfa_enabled = True
            # Save user object (in a real app, update DB)
            users[current_user.id] = current_user
            flash('MFA has been successfully enabled!', 'success')
            return redirect(url_for('profile'))
        else:
            flash('Invalid code. Please try again.', 'danger')

    return render_template('setup_mfa.html', qr_code=qr_code_base64, secret=current_user.mfa_secret)

@app.route('/disable-mfa', methods=['GET', 'POST'])
@login_required
def disable_mfa():
    if not current_user.mfa_enabled:
        flash('MFA is not currently enabled for your account.', 'info')
        return redirect(url_for('profile'))

    if request.method == 'POST':
        # For security, require re-authentication with MFA code
        otp_code = request.form.get('otp_code')
        if not otp_code:
            flash('Please enter your current MFA code to confirm.', 'warning')
            return render_template('disable_mfa.html')

        totp = pyotp.TOTP(current_user.mfa_secret)
        if totp.verify(otp_code):
            current_user.mfa_enabled = False
            # Option to also clear the secret, or keep it for easy re-enabling
            # current_user.mfa_secret = None
            # Save user object (in a real app, update DB)
            users[current_user.id] = current_user
            flash('MFA has been successfully disabled.', 'success')
            return redirect(url_for('profile'))
        else:
            flash('Invalid MFA code. MFA remains enabled.', 'danger')

    return render_template('disable_mfa.html')

@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    if request.method == 'POST':
        email = request.form.get('email')
        if not email:
            flash('Please enter your email address.', 'danger')
            return render_template('reset_mfa_request.html')

        user_id = users_by_email.get(email)
        user = users.get(user_id)

