        reset_token = str(uuid.uuid4())
        user.mfa_reset_token = reset_token
        user.mfa_reset_token_expires_at = datetime.utcnow() + timedelta(minutes=app.config['MFA_RESET_TOKEN_EXPIRATION_MINUTES'])
        users[user.id] = user # Save token to user object (update DB)

