@app.route('/reset-mfa/<token>')
def confirm_reset_mfa(token):
    user_to_reset = None
    for user in users.values():
        if user.mfa_reset_token == token:
            user_to_reset = user
            break

    if not user_to_reset:
        flash('Invalid or expired MFA reset link.', 'danger')
        return redirect(url_for('login'))

    if user_to_reset.mfa_reset_token_expires_at < datetime.utcnow():
        flash('MFA reset link has expired.', 'danger')
        user_to_reset.mfa_reset_token = None
        user_to_reset.mfa_reset_token_expires_at = None
        users[user_to_reset.id] = user_to_reset # Clear expired token
        return redirect(url_for('login'))

    # Disable MFA, clear secret, clear token
    user_to_reset.mfa_enabled = False
    user_to_reset.mfa_secret = None # Crucial to clear the secret
    user_to_reset.mfa_reset_token = None
    user_to_reset.mfa_reset_token_expires_at = None
    users[user_to_reset.id] = user_to_reset # Update user in store (update DB)

    flash('Your MFA settings have been successfully reset. You can now log in with just your password.', 'success')
    return redirect(url_for('login'))


